  1→import { useEffect, useRef, useState } from "react"
  2→import { useAuth } from "../../Context/useAuth";
  3→import { MoonLoader } from "react-spinners";
  4→import { addReply, getPostReplies } from "../../../API/Api";
  5→import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
  6→import { handleClickProfile } from "../../../helpers/handleClicks";
  7→import { useNavigate } from "react-router-dom";
  8→import { motion, AnimatePresence } from "framer-motion";
  9→import VerifiedBadge from "../Badge/VerifiedBadge";
 10→import formatPostDate from "../../../helpers/formatDateString";
 11→import ReplyContextChip from "./ReplyContextChip";
 12→import useTextareaMention from "../mentions/useTextareaMention";
 13→import MentionDropdown from "../mentions/MentionDropdown";
 14→
 15→const incrementReplyCount = (old, parentId) => {
 16→    if (!old || !Array.isArray(old.pages)) return old;
 17→
 18→    return {
 19→        ...old,
 20→        pages: old.pages.map((page) => ({
 21→            ...page,
 22→            comments: Array.isArray(page?.comments)
 23→                ? page.comments.map((comment) => {
 24→                    if (comment?.id !== parentId) return comment;
 25→                    return {
 26→                        ...comment,
 27→                        reply_count: (comment?.reply_count || 0) + 1,
 28→                    };
 29→                })
 30→                : page?.comments,
 31→        })),
 32→    };
 33→};
 34→
 35→
 36→const CommentsCards = ({comments, postId}) =>{
 37→    const {user, session} = useAuth();
 38→    const userId = user?.userData[0].id;
 39→    const queryClient = useQueryClient();
 40→
 41→    const [showReplyInput, setShowReplyInput] = useState(false);
 42→    const [showReplies, setShowReplies] = useState(false);
 43→
 44→    const [reply, setReply] = useState('')
 45→    const [replyLoaderId, setReplyLoaderId] = useState('');
 46→
 47→    const navigate = useNavigate();
 48→    const replyInputRef = useRef(null);
 49→
 50→    const { textareaProps: mentionTextareaProps, dropdownProps: mentionDropdownProps } = useTextareaMention(reply, setReply, replyInputRef, 200, userId);
 51→
 52→    const clickProfile = handleClickProfile(navigate);
 53→
 54→    const {data, isLoading, fetchNextPage, hasNextPage, isFetchinNextPage} = useInfiniteQuery({
 55→        queryKey: ['getPostReplies', comments.id],
 56→        queryFn: ({pageParam = null, queryKey}) => getPostReplies(queryKey[1], 5, pageParam),
 57→        getNextPageParam: (lastPage) => {
 58→            if(lastPage.hasMore){
 59→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 60→                return lastReply.id;
 61→            } else{
 62→                return undefined
 63→            }
 64→        },
 65→        refetchOnWindowFocus: false,
 66→        enabled: showReplies,
 67→        staleTime: 1000 * 60 * 5
 68→    })
 69→
 70→    const handleClickReplyButton = (e) =>{
 71→        e.stopPropagation();
 72→        setShowReplyInput(!showReplyInput);
 73→    }
 74→
 75→    const handleShowMoreReplies = () => {
 76→        if(!isFetchinNextPage){
 77→            fetchNextPage();
 78→        }
 79→    }
 80→
 81→    const submitReply = async(parent_id, receiver_id) => {
 82→        const trimmedReply = reply.trim();
 83→        if (!trimmedReply) return;
 84→
 85→        setReplyLoaderId(parent_id)
 86→        queryClient.cancelQueries({ queryKey: ['getPostReplies', parent_id] });
 87→        queryClient.cancelQueries({ queryKey: ['postComments', postId] });
 88→
 89→        const previousReplies = queryClient.getQueryData(['getPostReplies', parent_id]);
 90→        const previousComments = queryClient.getQueryData(['postComments', postId]);
 91→
 92→        const optimisticReply = {
 93→            id: `optimistic-reply-${Date.now()}`,
 94→            post_id: postId,
 95→            parent_id: parent_id,
 96→            comment: trimmedReply,
 97→            created_at: new Date().toISOString(),
 98→            user_id: user?.userData?.[0]?.id,
 99→            users: {
100→                id: user?.userData?.[0]?.id,
101→                name: user?.userData?.[0]?.name,
102→                image_url: user?.userData?.[0]?.image_url,
103→                badge: user?.userData?.[0]?.badge,
104→            },
105→            reply_count: 0,
106→        };
107→
108→        queryClient.setQueryData(['getPostReplies', parent_id], (old) => {
109→            if (!old || !Array.isArray(old.pages)) {
110→                return {
111→                    pageParams: [null],
112→                    pages: [{ data: [optimisticReply], hasMore: false }],
113→                };
114→            }
115→
116→            return {
117→                ...old,
118→                pages: old.pages.map((page, index) =>
119→                    index === 0
120→                        ? { ...page, data: [optimisticReply, ...(page?.data || [])] }
121→                        : page
122→                ),
123→            };
124→        });
125→        queryClient.setQueryData(['postComments', postId], (old) => incrementReplyCount(old, parent_id));
126→
127→        try {
128→            const formdata = new FormData();
129→            formdata.append('reply', trimmedReply);
130→
131→            const message = await addReply(userId, postId, parent_id, formdata, receiver_id, session?.access_token);
132→            if(message){
133→                // console.log(message);
134→            }
135→            queryClient.invalidateQueries({ queryKey: ['getPostReplies', parent_id] });
136→            queryClient.invalidateQueries({ queryKey: ['postComments', postId] });
137→            setReply('')
138→            setShowReplies(true)
139→        } catch (error) {
140→            queryClient.setQueryData(['getPostReplies', parent_id], previousReplies);
141→            queryClient.setQueryData(['postComments', postId], previousComments);
142→            setReply('')
143→            throw new Error('error adding replies')
144→        } finally {
145→            setReplyLoaderId('')
146→            setShowReplyInput(false);
147→        }
148→    }
149→
150→    useEffect(() =>{
151→        if(showReplyInput && replyInputRef.current){
152→            const timer = setTimeout(() => {
153→                replyInputRef.current.focus();
154→                replyInputRef.current.scrollIntoView({behavior: 'smooth', block: 'center'})
155→            }, 50);
156→
157→            return () => {
158→                clearTimeout(timer)
159→            }
160→        }
161→    }, [showReplyInput])
162→
163→    const replies = data?.pages.flatMap((page) => page.data) || [];
164→
165→    return(
166→        <div className={`cm-card ${comments?.parent_id ? 'cm-card--reply' : ''}`}>
167→            {comments?.parent_id && <div className="cm-thread-line" />}
168→
169→            <div className="cm-card-content">
170→                <div className="cm-user-row">
171→                    <div
172→                        onClick={(e) => clickProfile(e, user?.userData[0].id, comments?.user_id)}
173→                        className={`cm-avatar-container ${comments?.users?.badge === 'legend' ? 'cm-ring-legend' : comments?.users?.badge === 'og' ? 'cm-ring-og' : ''}`}
174→                    >
175→                        <img className="cm-avatar" src={comments?.users?.image_url || '/assets/profile.jpg'} alt={`${comments?.users?.name || "User"} profile picture`} />
176→                    </div>
177→                    <span
178→                        onClick={(e) => clickProfile(e, user?.userData[0].id, comments?.user_id)}
179→                        className="cm-username"
180→                    >
181→                        {comments?.users?.name}
182→                    </span>
183→                    <VerifiedBadge badge={comments?.users?.badge} size={14} />
184→                    <span className="cm-dot">&middot;</span>
185→                    <span className="cm-date">{formatPostDate(comments?.created_at)}</span>
186→                </div>
187→
188→                <p className="cm-body">{comments?.comment}</p>
189→
190→                <div className="cm-card-actions">
191→                    <button onClick={(e) => handleClickReplyButton(e)} className="cm-reply-btn">
192→                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
193→                            <polyline points="9 17 4 12 9 7" />
194→                            <path d="M20 18v-2a4 4 0 0 0-4-4H4" />
195→                        </svg>
196→                        Reply
197→                    </button>
198→
199→                    {comments?.reply_count > 0 && (
200→                        <button onClick={() => setShowReplies(!showReplies)} className="cm-toggle-replies-btn">
201→                            <motion.svg
202→                                width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"
203→                                animate={{ rotate: showReplies ? 180 : 0 }}
204→                                transition={{ duration: 0.2 }}
205→                            >
206→                                <polyline points="6 9 12 15 18 9" />
207→                            </motion.svg>
208→                            <span className="cm-replies-count-badge">{comments?.reply_count}</span>
209→                            {showReplies ? 'Hide replies' : 'View replies'}
210→                        </button>
211→                    )}
212→                </div>
213→
214→                {replyLoaderId === comments.id && (
215→                    <div className="cm-reply-loading">
216→                        <MoonLoader size={16} color="var(--loader-color)" speedMultiplier={0.8}/>
217→                    </div>
218→                )}
219→
220→                <AnimatePresence>
221→                    {showReplyInput && (
222→                        <motion.div
223→                            initial={{ height: 0, opacity: 0 }}
224→                            animate={{ height: "auto", opacity: 1 }}
225→                            exit={{ height: 0, opacity: 0 }}
226→                            transition={{ duration: 0.2 }}
227→                            className="cm-reply-input-wrapper"
228→                        >
229→                            <ReplyContextChip name={comments?.users?.name} onDismiss={(e) => handleClickReplyButton(e)} />
230→                            <textarea
231→                                ref={replyInputRef}
232→                                maxLength={200}
233→                                value={reply}
234→                                onChange={(e) => { setReply(e.target.value); mentionTextareaProps.onChange(e); }}
235→                                onKeyDown={mentionTextareaProps.onKeyDown}
236→                                onKeyUp={mentionTextareaProps.onKeyUp}
237→                                className="cm-reply-textarea"
238→                                placeholder={`Replying to ${comments?.users?.name}...`}
239→                                rows={1}
240→                            />
241→                            <MentionDropdown {...mentionDropdownProps} />
242→                            <div className="cm-reply-action-row">
243→                                <span className={`cm-reply-char-count ${reply.length > 199 ? 'cm-char-limit' : ''}`}>
244→                                    {reply.length}/200
245→                                </span>
246→                                <button
247→                                    onClick={() => submitReply(comments?.id, comments?.users?.id)}
248→                                    className="cm-reply-submit-btn"
249→                                    disabled={!reply.trim()}
250→                                >
251→                                    Submit
252→                                </button>
253→                            </div>
254→                        </motion.div>
255→                    )}
256→                </AnimatePresence>
257→
258→                <AnimatePresence>
259→                    {showReplies && (
260→                        <motion.div
261→                            initial={{ opacity: 0 }}
262→                            animate={{ opacity: 1 }}
263→                            exit={{ opacity: 0 }}
264→                            transition={{ duration: 0.2 }}
265→                            className="cm-replies-thread"
266→                        >
267→                            {replies?.map((r) => (
268→                                <CommentsCards postId={postId} key={r.id} comments={r}/>
269→                            ))}
270→
271→                            {hasNextPage && (
272→                                <button onClick={handleShowMoreReplies} className="cm-show-more-replies">
273→                                    {isFetchinNextPage ? 'Loading...' : 'Show more replies'}
274→                                </button>
275→                            )}
276→                        </motion.div>
277→                    )}
278→                </AnimatePresence>
279→            </div>
280→        </div>
281→    )
282→}
283→
284→export default CommentsCards;
