  1→import { useInfiniteQuery } from "@tanstack/react-query";
  2→import { useEffect } from "react";
  3→import { useLocation, useNavigate } from "react-router-dom";
  4→import { getUserOpinions } from "../../../API/Api";
  5→import { AnimatePresence, motion } from "framer-motion";
  6→import { useInView } from "react-intersection-observer";
  7→import VerifiedBadge from "../Badge/VerifiedBadge";
  8→import { useAuth } from "../../Context/useAuth";
  9→import { handleClickProfile } from "../../../helpers/handleClicks";
 10→import formatPostDate from "../../../helpers/formatDateString";
 11→import { MoonLoader } from "react-spinners";
 12→
 13→
 14→
 15→const VisitedProfileOpinions = () =>{
 16→    const {ref, inView} = useInView({threshold: 0, rootMargin: '200px'})
 17→    const location = useLocation();
 18→    const navigate = useNavigate();
 19→    const userId = location.state?.userId || new URLSearchParams(location.search).get('userId');
 20→   const {openAuthModal, session, user} = useAuth();;
 21→
 22→    const {data, isLoading, isFetchingNextPage, hasNextPage, fetchNextPage} = useInfiniteQuery({
 23→        queryKey: ['getUserOpinions', userId],
 24→        queryFn: ({pageParam = null, queryKey}) => getUserOpinions(pageParam, 5, queryKey[1]),
 25→        getNextPageParam: (lastPage) => {
 26→            if(lastPage.hasMore){
 27→                const lastOpinion = lastPage?.data[lastPage?.data.length - 1]
 28→                return lastOpinion.id;
 29→            } else {
 30→                return undefined
 31→            }
 32→        },
 33→        refetchOnWindowFocus: false,
 34→        enabled: !!userId,
 35→        staleTime: 1000 * 60 * 5
 36→    })
 37→
 38→
 39→    const handleClickOpionionsProfileOriginal = handleClickProfile(navigate);
 40→    const handleClickOpionionsProfile = (e, loggedInUserId, clickedUserId) => {
 41→        if(!session){
 42→            e.stopPropagation();
 43→            return openAuthModal();
 44→        }
 45→        handleClickOpionionsProfileOriginal(e, loggedInUserId, clickedUserId);
 46→    };
 47→
 48→    const handleClickContent = (e, opinionId, userId) =>{
 49→        e.stopPropagation();
 50→        if(!session) return openAuthModal();
 51→        navigate('/home/opinionsViewer', {
 52→            state: {
 53→                opinionId: opinionId,
 54→                userId: userId
 55→            }
 56→        })
 57→    }
 58→
 59→    useEffect(() =>{
 60→        // console.log(userId)
 61→    }, [userId])
 62→
 63→    useEffect(() =>{
 64→        if(inView && hasNextPage && !isFetchingNextPage){
 65→            fetchNextPage();
 66→        }
 67→    },[inView, hasNextPage, isFetchingNextPage, fetchNextPage])
 68→
 69→    const opinions = data?.pages?.flatMap((page) => page.data) || [];
 70→
 71→    if(isLoading){
 72→        return(
 73→            <div className="visited-profile-opinions-container">
 74→                <div className="opinions-loading-container">
 75→                    <MoonLoader size={25} color="var(--loader-color)" speedMultiplier={1} loading={isLoading}/>
 76→                </div>
 77→            </div>
 78→        )
 79→    }
 80→
 81→    if(opinions?.length === 0){
 82→        return(
 83→            <div className="visited-profile-opinions-container">
 84→                No opinions available
 85→            </div>
 86→        )
 87→    }
 88→
 89→    return(
 90→        <>
 91→        <AnimatePresence>
 92→        <div className="visited-profile-opinions-container">
 93→            {opinions.map((opinion) => (
 94→                <motion.div
 95→                    className="so-card-wrapper"
 96→                    key={opinion.id}
 97→                    initial={{ opacity: 0, y: 12 }}
 98→                    animate={{ opacity: 1, y: 0 }}
 99→                    transition={{ duration: 0.3, ease: "easeOut" }}
100→                >
101→                    <div className="so-card so-card--flat">
102→                        <div className="so-card-content">
103→                            <div className="so-user-row">
104→                                <div className="so-user-meta">
105→                                    <div className={`so-avatar-outer ${opinion.users.badge === 'legend' ? 'avatar-ring-legend' : opinion.users.badge === 'og' ? 'avatar-ring-og' : ''}`}>
106→                                        <img onClick={(e) => handleClickOpionionsProfile(e, user?.userData[0].id, userId)} className="so-avatar" src={opinion.users.image_url || "../../assets/profile.jpg"} alt={`${opinion?.users?.name || "User"} profile picture`} />
107→                                    </div>
108→                                    <div className="so-name-block">
109→                                        <div className="so-name-line">
110→                                            <span className="so-username">{opinion.users.name}</span>
111→                                            <VerifiedBadge badge={opinion.users.badge} size={14} />
112→                                        </div>
113→                                        <span className="so-handle">{formatPostDate(opinion.created_at)}</span>
114→                                    </div>
115→                                </div>
116→                            </div>
117→
118→                            <div
119→                                onClick={(e) => handleClickContent(e, opinion.id, opinion.users.id)}
120→                                className="so-body"
121→                            >
122→                                {opinion.opinion}
123→                            </div>
